INSERT INTO `announcements` VALUES ('a14f9146-41a1-4ba6-ae1b-d290b854b7c0','a14a96f2-006d-4232-973e-9683ef578737',2,'Q1 2026 Performance Review — Kick-off','Dear Team,\n\nThe Q1 2026 performance review cycle begins on 15 March 2026.\n\nAll staff are required to complete their self-assessment by 25 March. Line managers should submit their reviews by 31 March.\n\nPlease log in to the HR portal and navigate to Performance → My Reviews to get started.\n\nHR Department','high','all',NULL,'2026-03-11 02:18:37',NULL,1,1,'2026-03-16 02:18:37','2026-03-16 02:18:37'),('a14f9146-4667-431a-86d7-9cdadcfeed48','a14a96f2-006d-4232-973e-9683ef578737',2,'New Office Hours — Effective 1 April','Please note that effective 1 April 2026, our working hours will change to 8:00 AM – 5:00 PM Monday through Friday.\n\nThe Saturday roster schedule will be communicated separately by branch managers.','normal','all',NULL,'2026-03-11 02:18:37',NULL,0,1,'2026-03-16 02:18:37','2026-03-16 02:18:37'),('a14f9146-485a-44f3-83b4-0e089d1f7429','a14a96f2-006d-4232-973e-9683ef578737',2,'URGENT: System Maintenance — Sunday 22 March 02:00–06:00 AM','The core banking system will be down for scheduled maintenance this Sunday, 22 March 2026 between 02:00 AM and 06:00 AM.\n\nAll branch transactions must be completed before midnight on Saturday. Please plan accordingly and inform your customers.','urgent','all',NULL,'2026-03-12 02:18:37',NULL,1,1,'2026-03-16 02:18:37','2026-03-16 02:18:37'),('a14f9146-4aa0-4647-b8a9-40a56d740501','a14a96f2-006d-4232-973e-9683ef578737',2,'Staff Welfare: Annual Medical Check-up — March 2026','All permanent staff are reminded to complete their annual medical check-up at any of our approved clinics before 31 March 2026.\n\nPresent your staff ID to receive the discounted corporate rate. Submit your medical report to HR by email.','normal','all',NULL,'2026-03-13 02:18:37',NULL,0,1,'2026-03-16 02:18:37','2026-03-16 02:18:37'),('a14f9146-4cb9-4b9e-815e-ae737bfdbb86','a14a96f2-006d-4232-973e-9683ef578737',2,'IT Policy Update — Password Requirements','As part of our cybersecurity improvement initiative, all staff are required to update their system passwords by 20 March 2026.\n\nNew requirements: minimum 12 characters, must include uppercase, numbers, and a special character. Contact the IT helpdesk if you need assistance.','high','all',NULL,'2026-03-12 02:18:37',NULL,0,1,'2026-03-16 02:18:37','2026-03-16 02:18:37'),('a14fb644-ee1e-4fcb-b741-d0cf0185c7ff','a14a96f2-006d-4232-973e-9683ef578737',3,'Q1 2026 Performance Review — Action Required','All staff must complete their self-assessment forms on the HR portal before March 31, 2026. Line managers are to submit appraisal reports by April 7, 2026.','normal','all_staff',NULL,NULL,NULL,1,0,'2026-03-16 04:02:04','2026-03-16 04:02:04'),('a14fb644-f2a4-4540-8518-5de88db41485','a14a96f2-006d-4232-973e-9683ef578737',3,'Public Holiday: Easter Break (18–21 April 2026)','Please note that the bank will be closed for the Easter public holiday from Friday, 18 April to Monday, 21 April 2026. Normal banking operations resume Tuesday, 22 April 2026.','normal','all_staff',NULL,NULL,NULL,0,0,'2026-03-16 04:02:04','2026-03-16 04:02:04'),('a14fb644-f503-4411-a22e-6aa89b6e3dca','a14a96f2-006d-4232-973e-9683ef578737',3,'New CBN Directive on Customer KYC Documentation','Effective immediately, all new account openings must include BVN verification + NIN slip. Loan officers are to ensure all pending applications comply before disbursement.','normal','all_staff',NULL,NULL,NULL,1,0,'2026-03-16 04:02:04','2026-03-16 04:02:04'),('a14fb644-f7a8-4f12-b1c9-64dbf8605b21','a14a96f2-006d-4232-973e-9683ef578737',3,'Staff Welfare: NHIS Enrollment Deadline','The Health Insurance enrollment window closes April 30, 2026. Staff who have not yet completed their NHIS forms should visit HR before the deadline.','normal','all_staff',NULL,NULL,NULL,0,0,'2026-03-16 04:02:04','2026-03-16 04:02:04'),('a14fb644-fa89-410d-952f-57c1abe23dd5','a14a96f2-006d-4232-973e-9683ef578737',3,'IT Security Awareness: Password Update Required','As part of our quarterly security audit, all staff must update their system passwords by March 20, 2026. Passwords must be at least 12 characters.','normal','all_staff',NULL,NULL,NULL,0,0,'2026-03-16 04:02:04','2026-03-16 04:02:04');
/*!40000 ALTER TABLE `announcements` ENABLE KEYS */;
