INSERT INTO `disciplinary_cases` VALUES ('a14f4f77-d6f8-40ae-b527-d81d276f7c1f','a14a96f2-006d-4232-973e-9683ef578737','292e12f5-29f5-48a6-a8cf-a52e10a2b48f','DC-2026-0001','query','Staff repeatedly late to work (5 occasions Jan 2026) without notifying line manager. Breach of CBN conduct guidelines.','2026-01-15',2,'closed','2026-03-15 23:14:37','2026-03-15 23:14:37'),('a14f4f77-f197-4589-bb7c-c634feca3b9d','a14a96f2-006d-4232-973e-9683ef578737','3bb99f3b-2fa0-4011-a05f-41425b0d58df','DC-2026-0002','warning','Failed dual-control procedure on ₦500,000 cash withdrawal of Jan 27, 2026. Breach of Operational Risk Policy Section 3.2.','2026-01-28',2,'closed','2026-03-15 23:14:37','2026-03-15 23:14:37'),('a14f4f77-fcfa-4574-b49c-d021df077c5a','a14a96f2-006d-4232-973e-9683ef578737','4718d78a-0bcc-4804-aeac-0459fe703738','DC-2026-0003','query','Unprofessional behaviour during a customer loan inquiry on Feb 8, 2026. Customer filed a formal written complaint.','2026-02-10',2,'responded','2026-03-15 23:14:37','2026-03-15 23:14:37'),('a14f4f78-06a2-4253-8872-2346f75e1fb7','a14a96f2-006d-4232-973e-9683ef578737','49c7bcd1-040d-4072-b3f1-7d2566d0ad83','DC-2026-0004','suspension','Possible alteration of transaction records Feb 17, 2026 to conceal ₦180,000 cash shortage. CCTV and system logs preserved.','2026-02-20',2,'awaiting_response','2026-03-15 23:14:37','2026-03-15 23:14:37'),('a14f4f78-0bc8-4fac-960e-d539e96ccce8','a14a96f2-006d-4232-973e-9683ef578737','77622f07-245a-48ef-a17f-32d81e8c6947','DC-2026-0005','warning','Failed to complete mandatory CBN AML/CFT training by Feb 28 deadline despite two reminder emails (Feb 14, 21).','2026-03-03',2,'closed','2026-03-15 23:14:37','2026-03-15 23:18:25'),('a14f4f78-10ca-4797-b17c-2d31ba660d4a','a14a96f2-006d-4232-973e-9683ef578737','9f06e559-72ec-4d56-961e-847a5a1f250d','DC-2026-0006','query','Photographed customer account statements with personal mobile phone on Mar 5, 2026. Breach of NDPR 2019 and data security policy.','2026-03-08',2,'open','2026-03-15 23:14:37','2026-03-15 23:14:37'),('a14f4f78-1560-4544-b5c4-9c06b1d9317e','a14a96f2-006d-4232-973e-9683ef578737','b3e74912-cc6f-4d79-96ed-4f4fa6c9baf2','DC-2026-0007','warning','Approved ₦750,000 loan on Feb 3, 2026 without SMEDAN certificate and 6-month bank statement. Violation of credit approval procedures.','2026-02-05',2,'closed','2026-03-15 23:14:37','2026-03-15 23:14:37'),('a14f4f78-20cb-41b2-9e83-bf8c315da280','a14a96f2-006d-4232-973e-9683ef578737','ba5ec08d-0d14-4cb4-a0ba-83b60f78141c','DC-2026-0008','query','Missed three consecutive team meetings (Mar 3, 5, 10) without supervisor notification. Attendance is mandatory per HR policy.','2026-03-12',2,'open','2026-03-15 23:14:37','2026-03-15 23:14:37'),('a14f4f78-267e-4e5b-a752-3fc23b1f17ee','a14a96f2-006d-4232-973e-9683ef578737','bcbc3541-d080-4ffd-8717-3399d9e76b20','DC-2026-0009','suspension','Shared confidential customer account details via WhatsApp with an unauthorised third party on Feb 12, 2026. Severe NDPR breach.','2026-02-15',2,'closed','2026-03-15 23:14:37','2026-03-15 23:14:37'),('a14f4f78-326d-422e-8ac0-a27611adc94b','a14a96f2-006d-4232-973e-9683ef578737','cf9ca6fa-00e5-4776-99cb-8d98a2ef8a78','DC-2026-0010','query','Sleeping at workstation during banking hours on Jan 20 and 21, 2026. Unacceptable professional conduct.','2026-01-22',2,'closed','2026-03-15 23:14:37','2026-03-15 23:14:37');
