CREATE TABLE `kpi_notes` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tenant_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `author_id` bigint unsigned NOT NULL,
  `subject_type` varchar(30) COLLATE utf8mb4_unicode_ci NOT NULL,
  `subject_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `kpi_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `period_value` varchar(10) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `body` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_alert` tinyint(1) NOT NULL DEFAULT '0',
  `is_private` tinyint(1) NOT NULL DEFAULT '0',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `kpi_notes_author_id_foreign` (`author_id`),
  KEY `kpi_notes_kpi_id_foreign` (`kpi_id`),
  KEY `kpi_notes_tenant_id_subject_type_subject_id_index` (`tenant_id`,`subject_type`,`subject_id`),
  KEY `kpi_notes_tenant_id_author_id_index` (`tenant_id`,`author_id`),
  CONSTRAINT `kpi_notes_author_id_foreign` FOREIGN KEY (`author_id`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `kpi_notes_kpi_id_foreign` FOREIGN KEY (`kpi_id`) REFERENCES `kpi_definitions` (`id`) ON DELETE SET NULL,
  CONSTRAINT `kpi_notes_tenant_id_foreign` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
