  `subject_ref_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `period_value` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL,
  `period_type` enum('monthly','quarterly','yearly') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'monthly',
  `achievement_pct` decimal(8,2) DEFAULT NULL,
  `severity` enum('green','yellow','red','info') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'info',
  `recommendation_type` enum('below_target','improving','declining','consistent_underperformer','top_performer','milestone_reached','custom') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'custom',
  `title` varchar(200) COLLATE utf8mb4_unicode_ci NOT NULL,
