DROP TABLE IF EXISTS `kpi_targets`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `kpi_targets` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tenant_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `kpi_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `target_type` enum('individual','team','branch','department','tenant') COLLATE utf8mb4_unicode_ci NOT NULL,
  `target_ref_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `target_ref_type` varchar(30) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `department` varchar(50) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `period_type` enum('monthly','quarterly','yearly') COLLATE utf8mb4_unicode_ci NOT NULL,
  `period_value` varchar(10) COLLATE utf8mb4_unicode_ci NOT NULL,
  `parent_target_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `weight_pct` decimal(5,2) NOT NULL DEFAULT '100.00',
  `is_cascaded` tinyint(1) NOT NULL DEFAULT '0',
  `target_value` decimal(20,4) NOT NULL,
  `alert_threshold_pct` tinyint unsigned NOT NULL DEFAULT '70',
  `set_by` bigint unsigned NOT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `kpi_targets_unique` (`tenant_id`,`kpi_id`,`target_type`,`target_ref_id`,`period_type`,`period_value`),
  KEY `kpi_targets_kpi_id_foreign` (`kpi_id`),
  KEY `kpi_targets_set_by_foreign` (`set_by`),
  KEY `kpi_targets_tenant_id_period_type_period_value_index` (`tenant_id`,`period_type`,`period_value`),
  KEY `kpi_targets_tenant_id_target_type_target_ref_id_index` (`tenant_id`,`target_type`,`target_ref_id`),
  CONSTRAINT `kpi_targets_kpi_id_foreign` FOREIGN KEY (`kpi_id`) REFERENCES `kpi_definitions` (`id`) ON DELETE CASCADE,
  CONSTRAINT `kpi_targets_set_by_foreign` FOREIGN KEY (`set_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `kpi_targets_tenant_id_foreign` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
