INSERT INTO `notification_templates` VALUES ('a14a98e9-ca22-4d3b-bbba-17f1eea85fd8','a14a96f2-006d-4232-973e-9683ef578737','loan_disbursed','sms',NULL,'Dear {{customer_name}}, your loan of NGN {{amount}} has been disbursed to your account {{account_number}}. Repayment starts {{first_repayment_date}}. - Demo MFB',1,'2026-03-13 15:00:51','2026-03-13 15:00:51'),('a14a98e9-d70f-49bb-94d3-da2a9e90194e','a14a96f2-006d-4232-973e-9683ef578737','loan_disbursed','email','Loan Disbursement Confirmation','Dear {{customer_name}},\n\nYour loan application has been approved and NGN {{amount}} has been credited to your account.\n\nLoan Account: {{loan_account_number}}\nFirst Repayment: {{first_repayment_date}}\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:00:51','2026-03-13 15:00:51'),('a14a98e9-dc6a-4985-896d-8f601ddabda0','a14a96f2-006d-4232-973e-9683ef578737','repayment_received','sms',NULL,'Dear {{customer_name}}, we received your repayment of NGN {{amount}} on {{date}}. Outstanding balance: NGN {{outstanding_balance}}. - Demo MFB',1,'2026-03-13 15:00:51','2026-03-13 15:00:51'),('a14a98e9-e0a6-46fa-9405-815a65278e13','a14a96f2-006d-4232-973e-9683ef578737','loan_approved','sms',NULL,'Dear {{customer_name}}, your loan application of NGN {{amount}} has been approved. You will be contacted for disbursement. - Demo MFB',1,'2026-03-13 15:00:51','2026-03-13 15:00:51'),('a14a98e9-e401-4d0d-a6e7-1e6566b3b4a5','a14a96f2-006d-4232-973e-9683ef578737','account_opened','sms',NULL,'Dear {{customer_name}}, your savings account {{account_number}} has been opened successfully. Welcome to Demo MFB!',1,'2026-03-13 15:00:51','2026-03-13 15:00:51'),('a14a98e9-e7c6-4863-bc6c-4180220a3940','a14a96f2-006d-4232-973e-9683ef578737','kyc_approved','sms',NULL,'Dear {{customer_name}}, your KYC verification is complete. Your account is now fully activated. - Demo MFB',1,'2026-03-13 15:00:51','2026-03-13 15:00:51'),('a14a98e9-ebcc-48d9-87e9-6cf64bde8875','a14a96f2-006d-4232-973e-9683ef578737','loan_overdue','sms',NULL,'Dear {{customer_name}}, your loan repayment of NGN {{amount}} was due on {{due_date}}. Please pay immediately to avoid penalties. - Demo MFB',1,'2026-03-13 15:00:51','2026-03-13 15:00:51'),('a14aa7d3-5b48-45e8-acdd-21d85cdae6eb','a14a96f2-006d-4232-973e-9683ef578737','loan_approved','email','Your Loan Application Has Been Approved – {{loan_number}}','Dear {{customer_name}},\n\nCongratulations! Your loan application has been approved.\n\nLoan Reference: {{loan_number}}\nApproved Amount: NGN {{amount}}\nProduct: {{product_name}}\nTenure: {{tenure}}\n\nOur team will contact you shortly to complete the disbursement process.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:42:32','2026-03-13 15:42:32'),('a14aa7d3-6256-4d8a-967e-e70f71ca0d85','a14a96f2-006d-4232-973e-9683ef578737','loan_rejected','sms',NULL,'Dear {{customer_name}}, we regret to inform you that your loan application of NGN {{amount}} has not been approved at this time. Please visit a branch for details. - Demo MFB',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-64d3-461a-9057-bcc573902a9f','a14a96f2-006d-4232-973e-9683ef578737','loan_rejected','email','Update on Your Loan Application','Dear {{customer_name}},\n\nThank you for applying for a loan with Demo Microfinance Bank.\n\nAfter careful review, we regret to inform you that your loan application of NGN {{amount}} could not be approved at this time.\n\nReason: {{reason}}\n\nYou are welcome to re-apply after addressing the above or visit your nearest branch to speak with a loan officer.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-6775-45eb-ac1e-1bb604ee4904','a14a96f2-006d-4232-973e-9683ef578737','repayment_received','email','Repayment Received – NGN {{amount}}','Dear {{customer_name}},\n\nWe have received your loan repayment. Here are the details:\n\nAmount Paid: NGN {{amount}}\nPayment Date: {{date}}\nLoan Reference: {{loan_number}}\nOutstanding Balance: NGN {{outstanding_balance}}\n\nThank you for keeping up with your repayments.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-6992-4840-bb1f-955c99fd301e','a14a96f2-006d-4232-973e-9683ef578737','repayment_overdue','sms',NULL,'URGENT: Dear {{customer_name}}, your loan repayment of NGN {{amount}} was due on {{due_date}} and is now overdue. Please pay immediately to avoid penalties. - Demo MFB',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-6b44-40b6-b4cf-3225c858c098','a14a96f2-006d-4232-973e-9683ef578737','repayment_overdue','email','URGENT: Overdue Loan Repayment – {{loan_number}}','Dear {{customer_name}},\n\nThis is an urgent reminder that your loan repayment is overdue.\n\nLoan Reference: {{loan_number}}\nAmount Due: NGN {{amount}}\nDue Date: {{due_date}}\nDays Overdue: {{days_overdue}}\n\nPlease make this payment immediately to avoid late charges and adverse credit reporting. You can visit any of our branches or make a transfer to your loan account.\n\nIf you have already made this payment, please disregard this notice.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-6dca-4f88-a17f-9c24a93cbe45','a14a96f2-006d-4232-973e-9683ef578737','repayment_reminder','sms',NULL,'Dear {{customer_name}}, friendly reminder: your loan repayment of NGN {{amount}} is due on {{due_date}}. Please ensure your account is funded. - Demo MFB',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-6ffb-42df-9a51-cbf1043a2016','a14a96f2-006d-4232-973e-9683ef578737','repayment_reminder','email','Upcoming Loan Repayment Reminder – {{loan_number}}','Dear {{customer_name}},\n\nThis is a friendly reminder that your upcoming loan repayment is due soon.\n\nLoan Reference: {{loan_number}}\nAmount Due: NGN {{amount}}\nDue Date: {{due_date}}\n\nPlease ensure your account is adequately funded before the due date to avoid late fees.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-72a2-4ce4-8cb0-972f57b6dba7','a14a96f2-006d-4232-973e-9683ef578737','kyc_approved','email','KYC Verification Successful – Account Activated','Dear {{customer_name}},\n\nWe are pleased to inform you that your identity verification (KYC) has been successfully completed.\n\nKYC Tier: {{kyc_tier}}\nAccount Status: Active\n\nYou can now access all banking services including loans and transfers. Log in to your account to get started.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-74b2-4f8d-91c2-b2df9f77dddf','a14a96f2-006d-4232-973e-9683ef578737','kyc_rejected','sms',NULL,'Dear {{customer_name}}, your KYC verification was unsuccessful. Please visit a branch with valid ID documents to retry. - Demo MFB',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-76fc-48d1-9349-b66cf1a6a5fa','a14a96f2-006d-4232-973e-9683ef578737','kyc_rejected','email','Action Required: KYC Verification Unsuccessful','Dear {{customer_name}},\n\nUnfortunately, we were unable to complete your identity verification (KYC).\n\nReason: {{reason}}\n\nTo resolve this, please visit your nearest Demo MFB branch with the following:\n- A valid government-issued ID (National ID, Driver\'s License, or International Passport)\n- Proof of address (utility bill or bank statement)\n\nOur compliance team is available to assist you.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-7a26-463e-b20a-104920fe94b9','a14a96f2-006d-4232-973e-9683ef578737','account_opened','email','Welcome to Demo MFB – Your Account is Ready','Dear {{customer_name}},\n\nWelcome to Demo Microfinance Bank! Your account has been successfully opened.\n\nAccount Number: {{account_number}}\nAccount Name: {{account_name}}\nProduct: {{product_name}}\nCurrency: {{currency}}\n\nYou can now make deposits, transfers, and apply for our loan products. If you have any questions, please don\'t hesitate to contact us.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-7c9b-49f6-9258-a35278da6516','a14a96f2-006d-4232-973e-9683ef578737','transfer_received','sms',NULL,'Dear {{customer_name}}, you have received an inbound transfer of NGN {{amount}} from {{sender_name}}. New balance: NGN {{new_balance}}. - Demo MFB',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-7f1b-4fd0-a521-2853474e283c','a14a96f2-006d-4232-973e-9683ef578737','transfer_received','email','Credit Alert – NGN {{amount}} Received','Dear {{customer_name}},\n\nA transfer has been credited to your account.\n\nAmount: NGN {{amount}}\nSender: {{sender_name}}\nDate: {{date}}\nReference: {{reference}}\nNew Balance: NGN {{new_balance}}\n\nIf you did not expect this credit, please contact us immediately.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-815b-40ab-a418-b5f3c814cf71','a14a96f2-006d-4232-973e-9683ef578737','otp','sms',NULL,'Your Demo MFB verification code is: {{otp_code}}. Valid for {{expiry_minutes}} minutes. Do not share this code with anyone.',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-83d7-4c5d-80f6-3d1e5d291fc8','a14a96f2-006d-4232-973e-9683ef578737','otp','email','Your Verification Code','Dear {{customer_name}},\n\nYour one-time verification code is:\n\n{{otp_code}}\n\nThis code is valid for {{expiry_minutes}} minutes. Do not share it with anyone — Demo MFB staff will never ask for your OTP.\n\nIf you did not request this code, please contact us immediately.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aa7d3-85cc-4925-a714-4eec2a2ff599','a14a96f2-006d-4232-973e-9683ef578737','password_reset','email','Password Reset Request','Dear {{customer_name}},\n\nWe received a request to reset the password for your account.\n\nClick the link below to reset your password (valid for {{expiry_minutes}} minutes):\n\n{{reset_link}}\n\nIf you did not request a password reset, please ignore this email or contact us if you believe your account may be compromised.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:42:33','2026-03-13 15:42:33'),('a14aaa79-0f72-4ce7-a551-813f2226d329','a14a96f2-006d-4232-973e-9683ef578737','loan_topup_approved','sms',NULL,'Dear {{customer_name}}, your loan top-up of NGN {{topup_amount}} has been approved. New loan {{new_loan_number}} (NGN {{new_principal}}, {{new_tenure}}) created. - Demo MFB',1,'2026-03-13 15:49:57','2026-03-13 15:49:57'),('a14aaa79-160e-4ed5-96b6-0e884aed165f','a14a96f2-006d-4232-973e-9683ef578737','loan_topup_approved','email','Loan Top-up Approved – {{new_loan_number}}','Dear {{customer_name}},\n\nYour loan top-up request has been approved and funds have been credited to your account.\n\nNew Loan Reference: {{new_loan_number}}\nTop-up Amount Disbursed: NGN {{topup_amount}}\nNew Combined Principal: NGN {{new_principal}}\nNew Interest Rate: {{new_rate}}\nNew Tenure: {{new_tenure}}\nDisbursement Account: {{account_number}}\n\nYour previous loan has been closed and replaced by the new loan above.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:49:57','2026-03-13 15:49:57'),('a14aaa79-18bc-487a-99cc-cba28777ee09','a14a96f2-006d-4232-973e-9683ef578737','loan_topup_rejected','sms',NULL,'Dear {{customer_name}}, your top-up request of NGN {{topup_amount}} on loan {{original_loan_number}} was not approved. Please visit a branch for details. - Demo MFB',1,'2026-03-13 15:49:57','2026-03-13 15:49:57'),('a14aaa79-1aee-4f0a-9ac5-421c6c976822','a14a96f2-006d-4232-973e-9683ef578737','loan_topup_rejected','email','Loan Top-up Request Unsuccessful','Dear {{customer_name}},\n\nWe regret to inform you that your loan top-up request has not been approved at this time.\n\nOriginal Loan: {{original_loan_number}}\nRequested Top-up: NGN {{topup_amount}}\nReason: {{reason}}\n\nPlease visit your nearest branch or speak with your loan officer if you have questions.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:49:57','2026-03-13 15:49:57'),('a14aaa79-1d32-466d-8af8-6232f5b5f843','a14a96f2-006d-4232-973e-9683ef578737','loan_restructured','sms',NULL,'Dear {{customer_name}}, your loan has been restructured. New loan {{new_loan_number}} (NGN {{new_outstanding}}, {{new_tenure}} at {{new_rate}}) replaces {{old_loan_number}}. - Demo MFB',1,'2026-03-13 15:49:57','2026-03-13 15:49:57'),('a14aaa79-1eb9-497c-8642-46af3c161c1c','a14a96f2-006d-4232-973e-9683ef578737','loan_restructured','email','Your Loan Has Been Restructured – {{new_loan_number}}','Dear {{customer_name}},\n\nYour loan restructure request has been approved. Your loan has been rescheduled on new terms.\n\nPrevious Loan: {{old_loan_number}}\nPrevious Outstanding: NGN {{previous_outstanding}}\n\nNew Loan Reference: {{new_loan_number}}\nNew Outstanding Balance: NGN {{new_outstanding}}\nNew Interest Rate: {{new_rate}}\nNew Tenure: {{new_tenure}}\n\nYour previous loan has been closed and the new loan is now active. Please ensure timely repayments on the new schedule.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:49:57','2026-03-13 15:49:57'),('a14aaa79-208e-41ea-bd10-c64925274ae2','a14a96f2-006d-4232-973e-9683ef578737','loan_restructure_rejected','sms',NULL,'Dear {{customer_name}}, your restructure request on loan {{loan_number}} was not approved. Please visit a branch for details. - Demo MFB',1,'2026-03-13 15:49:57','2026-03-13 15:49:57'),('a14aaa79-225b-45e3-97c1-6b5618fc1f36','a14a96f2-006d-4232-973e-9683ef578737','loan_restructure_rejected','email','Loan Restructure Request Not Approved','Dear {{customer_name}},\n\nWe regret to inform you that your loan restructure request has not been approved at this time.\n\nLoan Reference: {{loan_number}}\nReason: {{reason}}\n\nYour existing loan remains active under its current terms. Please visit your nearest branch or contact your loan officer for further assistance.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:49:57','2026-03-13 15:49:57'),('a14aaa79-24bf-435b-9e6c-bfe20ed39849','a14a96f2-006d-4232-973e-9683ef578737','loan_liquidation_partial','sms',NULL,'Dear {{customer_name}}, a partial payment of NGN {{amount}} has been applied to loan {{loan_number}}. Remaining balance: NGN {{outstanding_balance}} (Ref: {{reference}}). - Demo MFB',1,'2026-03-13 15:49:57','2026-03-13 15:49:57'),('a14aaa79-26ba-4d48-83bd-d2ea6c9e2f8d','a14a96f2-006d-4232-973e-9683ef578737','loan_liquidation_partial','email','Partial Loan Payment Received – {{loan_number}}','Dear {{customer_name}},\n\nA partial lump-sum payment has been applied to your loan.\n\nLoan Reference: {{loan_number}}\nAmount Applied: NGN {{amount}}\nRemaining Balance: NGN {{outstanding_balance}}\nTransaction Ref: {{reference}}\n\nThank you. Please continue making regular repayments as scheduled.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:49:57','2026-03-13 15:49:57'),('a14aaa79-289c-41af-bb93-6867c52de93f','a14a96f2-006d-4232-973e-9683ef578737','loan_liquidation_full','sms',NULL,'Congratulations {{customer_name}}! Your loan {{loan_number}} has been fully settled. NGN {{discount_amount}} interest rebated. Your loan is now closed. - Demo MFB',1,'2026-03-13 15:49:57','2026-03-13 15:49:57'),('a14aaa79-2b85-4af3-9cf6-8298d3884596','a14a96f2-006d-4232-973e-9683ef578737','loan_liquidation_full','email','Loan Fully Settled – {{loan_number}} is Now Closed','Dear {{customer_name}},\n\nCongratulations! Your loan has been fully settled and closed.\n\nLoan Reference: {{loan_number}}\nAmount Paid: NGN {{amount}}\nUnearned Interest Rebated: NGN {{discount_amount}}\nTransaction Ref: {{reference}}\nStatus: CLOSED\n\nThank you for banking with Demo Microfinance Bank. You are welcome to apply for a new loan at any time.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 15:49:57','2026-03-13 15:49:57'),('a14ab116-d8b6-42d9-8e6e-ecfff89ebc1f','a14a96f2-006d-4232-973e-9683ef578737','deposit_received','sms',NULL,'Credit Alert: NGN {{amount}} deposited to {{account_number}} on {{date}}. Desc: {{description}}. Bal: NGN {{new_balance}}. Ref: {{reference}}. - Demo MFB',1,'2026-03-13 16:08:27','2026-03-13 16:08:27'),('a14ab116-e08e-40ec-b161-6e41bbe1bd9c','a14a96f2-006d-4232-973e-9683ef578737','deposit_received','email','Credit Alert – NGN {{amount}} Credited to {{account_number}}','Dear {{customer_name}},\n\nYour account has been credited.\n\nAmount: {{currency}} {{amount}}\nAccount: {{account_number}}\nDescription: {{description}}\nTransaction Ref: {{reference}}\nDate: {{date}}\nNew Balance: {{currency}} {{new_balance}}\n\nIf you did not authorise this transaction, please contact us immediately.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 16:08:27','2026-03-13 16:08:27'),('a14ab116-e444-4c72-a82d-5c8ed485d3db','a14a96f2-006d-4232-973e-9683ef578737','withdrawal_posted','sms',NULL,'Debit Alert: NGN {{amount}} withdrawn from {{account_number}} on {{date}}. Desc: {{description}}. Bal: NGN {{new_balance}}. Ref: {{reference}}. - Demo MFB',1,'2026-03-13 16:08:27','2026-03-13 16:08:27'),('a14ab116-ebc1-4049-a3a4-fb37d6be701b','a14a96f2-006d-4232-973e-9683ef578737','withdrawal_posted','email','Debit Alert – NGN {{amount}} Withdrawn from {{account_number}}','Dear {{customer_name}},\n\nA withdrawal has been posted to your account.\n\nAmount: {{currency}} {{amount}}\nAccount: {{account_number}}\nDescription: {{description}}\nTransaction Ref: {{reference}}\nDate: {{date}}\nNew Balance: {{currency}} {{new_balance}}\n\nIf you did not authorise this transaction, please contact us immediately.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 16:08:27','2026-03-13 16:08:27'),('a14ab116-f03d-4de9-9167-f6f755c20914','a14a96f2-006d-4232-973e-9683ef578737','transfer_sent','sms',NULL,'Debit Alert: NGN {{amount}} transferred from {{from_account}} to {{to_account}} on {{date}}. Bal: NGN {{new_balance}}. Ref: {{reference}}. - Demo MFB',1,'2026-03-13 16:08:27','2026-03-13 16:08:27'),('a14ab116-f44b-45c4-a822-5299a2e1873c','a14a96f2-006d-4232-973e-9683ef578737','transfer_sent','email','Transfer Debit Alert – NGN {{amount}} Sent','Dear {{customer_name}},\n\nA transfer has been debited from your account.\n\nAmount: {{currency}} {{amount}}\nFrom Account: {{from_account}}\nTo Account: {{to_account}} ({{beneficiary_name}})\nDescription: {{description}}\nTransaction Ref: {{reference}}\nDate: {{date}}\nNew Balance: {{currency}} {{new_balance}}\n\nIf you did not authorise this transfer, please contact us immediately.\n\nRegards,\nDemo Microfinance Bank',1,'2026-03-13 16:08:27','2026-03-13 16:08:27');
/*!40000 ALTER TABLE `notification_templates` ENABLE KEYS */;
UNLOCK TABLES;

--
-- Table structure for table `notifications`
--

DROP TABLE IF EXISTS `notifications`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `notifications` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `type` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `notifiable_type` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `notifiable_id` bigint unsigned NOT NULL,
  `data` text COLLATE utf8mb4_unicode_ci NOT NULL,
  `read_at` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `notifications_notifiable_type_notifiable_id_index` (`notifiable_type`,`notifiable_id`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

--
-- Dumping data for table `notifications`
--

LOCK TABLES `notifications` WRITE;
