DROP TABLE IF EXISTS `payroll_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `payroll_items` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `payroll_run_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `staff_profile_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `gross_salary` decimal(15,2) NOT NULL,
  `taxable_income` decimal(15,2) NOT NULL,
  `total_deductions` decimal(15,2) NOT NULL,
  `paye` decimal(15,2) NOT NULL DEFAULT '0.00',
  `employee_pension` decimal(15,2) NOT NULL DEFAULT '0.00',
  `employer_pension` decimal(15,2) NOT NULL DEFAULT '0.00',
  `nhf` decimal(15,2) NOT NULL DEFAULT '0.00',
  `nsitf` decimal(15,2) NOT NULL DEFAULT '0.00',
  `net_salary` decimal(15,2) NOT NULL,
  `bank_detail_id` char(36) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `payment_status` enum('pending','paid','failed') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'pending',
  `payment_date` timestamp NULL DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `payroll_items_payroll_run_id_staff_profile_id_unique` (`payroll_run_id`,`staff_profile_id`),
  KEY `payroll_items_staff_profile_id_foreign` (`staff_profile_id`),
  KEY `payroll_items_bank_detail_id_foreign` (`bank_detail_id`),
  KEY `payroll_items_payroll_run_id_payment_status_index` (`payroll_run_id`,`payment_status`),
  CONSTRAINT `payroll_items_bank_detail_id_foreign` FOREIGN KEY (`bank_detail_id`) REFERENCES `staff_bank_details` (`id`) ON DELETE SET NULL,
  CONSTRAINT `payroll_items_payroll_run_id_foreign` FOREIGN KEY (`payroll_run_id`) REFERENCES `payroll_runs` (`id`) ON DELETE CASCADE,
  CONSTRAINT `payroll_items_staff_profile_id_foreign` FOREIGN KEY (`staff_profile_id`) REFERENCES `staff_profiles` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

