DROP TABLE IF EXISTS `payroll_runs`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `payroll_runs` (
  `id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `tenant_id` char(36) COLLATE utf8mb4_unicode_ci NOT NULL,
  `period_month` tinyint unsigned NOT NULL,
  `period_year` smallint unsigned NOT NULL,
  `status` enum('draft','processing','approved','paid','cancelled') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'draft',
  `total_gross` decimal(20,2) NOT NULL DEFAULT '0.00',
  `total_deductions` decimal(20,2) NOT NULL DEFAULT '0.00',
  `total_net` decimal(20,2) NOT NULL DEFAULT '0.00',
  `total_paye` decimal(20,2) NOT NULL DEFAULT '0.00',
  `total_pension_employee` decimal(20,2) NOT NULL DEFAULT '0.00',
  `total_pension_employer` decimal(20,2) NOT NULL DEFAULT '0.00',
  `total_nhf` decimal(20,2) NOT NULL DEFAULT '0.00',
  `total_nsitf` decimal(20,2) NOT NULL DEFAULT '0.00',
  `staff_count` int NOT NULL DEFAULT '0',
  `run_by` bigint unsigned NOT NULL,
  `approved_by` bigint unsigned DEFAULT NULL,
  `approved_at` timestamp NULL DEFAULT NULL,
  `paid_at` timestamp NULL DEFAULT NULL,
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `payroll_runs_tenant_id_period_month_period_year_unique` (`tenant_id`,`period_month`,`period_year`),
  KEY `payroll_runs_run_by_foreign` (`run_by`),
  KEY `payroll_runs_approved_by_foreign` (`approved_by`),
  CONSTRAINT `payroll_runs_approved_by_foreign` FOREIGN KEY (`approved_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `payroll_runs_run_by_foreign` FOREIGN KEY (`run_by`) REFERENCES `users` (`id`) ON DELETE CASCADE,
  CONSTRAINT `payroll_runs_tenant_id_foreign` FOREIGN KEY (`tenant_id`) REFERENCES `tenants` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
