INSERT INTO `support_kb_articles` VALUES ('a14fab6a-be05-4355-971f-90008ece4f9a','a14a96f2-006d-4232-973e-9683ef578737',2,'How to reset internet banking password','1. Verify customer with BVN and date of birth.\n2. Navigate Admin > Users > Customer Accounts.\n3. Search by account number.\n4. Click Reset Password.\n5. Customer receives temporary password by email.\n\nAlways log the reset in customer interaction notes.','Account Issues','published',0,0,'2026-03-16 03:31:43','2026-03-16 03:31:43'),('a14fab6a-c31e-4857-88bd-5322546cffa0','a14a96f2-006d-4232-973e-9683ef578737',2,'POS dispute resolution process','1. Collect POS receipt or screenshot.\n2. Note terminal ID, date, time, and amount.\n3. Raise dispute ticket: DISP-[date]-[acctno].\n4. Escalate to Cards team within 24 hours.\n5. Provisional credit after 48 hours per CBN guidelines.\n\nResolve within 5 business days.','Cards','published',0,0,'2026-03-16 03:31:43','2026-03-16 03:31:43'),('a14fab6a-c6be-4ffd-9513-662194376967','a14a96f2-006d-4232-973e-9683ef578737',2,'USSD banking codes and limits','Transfer: *921*[amount]*[account]#\nBalance: *921*0#\nMini-statement: *921*9#\n\nDaily limits: Basic N20k | Standard N100k | Premium N1M','USSD','published',0,0,'2026-03-16 03:31:43','2026-03-16 03:31:43'),('a14fab6a-ca1e-407f-a68c-c9668053805a','a14a96f2-006d-4232-973e-9683ef578737',2,'Account freeze and unfreeze procedure','Frozen by: Court order, Compliance flag, or Customer request.\n\nTo unfreeze: Get clearance from Compliance, document resolution, Branch Manager approval for >N500k. Notify customer.','Compliance','published',0,0,'2026-03-16 03:31:43','2026-03-16 03:31:43');
/*!40000 ALTER TABLE `support_kb_articles` ENABLE KEYS */;
UNLOCK TABLES;

